import json
import re
from flask import Flask, request, jsonify
from elasticsearch import Elasticsearch

app = Flask(__name__)

# Elasticsearch client configuration
es = Elasticsearch(
    hosts=[{"host": "localhost", "port": 9200}],
    timeout=30,
)

# Allowlist of safe aggregation types
ALLOWED_AGG_TYPES = {"sum", "avg", "min", "max", "value_count", "cardinality", "stats", "extended_stats"}

# Allowlist of safe script languages
ALLOWED_LANGUAGES = {"painless"}

# Pattern to detect dangerous operations in Painless scripts
DANGEROUS_PATTERNS = [
    r'\bRuntime\b',
    r'\bProcessBuilder\b',
    r'\bgetRuntime\b',
    r'\bexec\b',
    r'\bThread\b',
    r'\bClass\b',
    r'\bforName\b',
    r'\bgetClass\b',
    r'\bClassLoader\b',
    r'\bjava\.lang\b',
    r'\bjava\.io\b',
    r'\bjava\.net\b',
    r'\bjava\.nio\b',
    r'\bFile\b',
    r'\bSocket\b',
    r'\bURL\b',
    r'\bSystem\b',
    r'\bReflect\b',
    r'\bnewInstance\b',
    r'\bgetMethod\b',
    r'\binvoke\b',
    r'\bgetDeclaredMethod\b',
    r'\bgetDeclaredField\b',
    r'\bsetAccessible\b',
    r'\bScriptEngine\b',
    r'\bGroovy\b',
    r'\bjavax\b',
    r'import\s',
    r'\bProcess\b',
    r'\bRuntime\.getRuntime\b',
    r'\bInetAddress\b',
]

# Allowlist of permitted field operations in scripts
ALLOWED_SCRIPT_PATTERNS = [
    r"^[\s]*doc\['.+?'\]\.value[\s]*$",
    r"^[\s]*doc\['.+?'\]\.value\s*[\+\-\*/%]\s*\d+[\s]*$",
    r"^[\s]*doc\['.+?'\]\.value\s*[\+\-\*/%]\s*doc\['.+?'\]\.value[\s]*$",
    r"^[\s]*params\.\w+\s*[\+\-\*/%]\s*doc\['.+?'\]\.value[\s]*$",
    r"^[\s]*doc\['.+?'\]\.value\s*[\+\-\*/%]\s*params\.\w+[\s]*$",
    r"^[\s]*Math\.\w+\(.*\)[\s]*$",
    r"^[\s]*\d+[\s]*$",
    r"^[\s]*doc\['.+?'\]\.size\(\)\s*[><=!]+\s*\d+\s*\?\s*doc\['.+?'\]\.value\s*:\s*\d+[\s]*$",
]

# Maximum script length
MAX_SCRIPT_LENGTH = 500


def validate_script(script_source):
    """
    Validate a script source string to prevent code injection and dangerous operations.
    Uses an allowlist approach - only permits known safe patterns.
    """
    if not isinstance(script_source, str):
        return False, "Script source must be a string"

    if len(script_source) > MAX_SCRIPT_LENGTH:
        return False, f"Script exceeds maximum length of {MAX_SCRIPT_LENGTH} characters"

    if not script_source.strip():
        return False, "Script source cannot be empty"

    # Check for dangerous patterns (blocklist as defense-in-depth)
    for pattern in DANGEROUS_PATTERNS:
        if re.search(pattern, script_source, re.IGNORECASE):
            return False, f"Script contains disallowed pattern: {pattern}"

    # Verify script matches at least one allowed pattern (allowlist)
    script_stripped = script_source.strip()
    is_allowed = False
    for pattern in ALLOWED_SCRIPT_PATTERNS:
        if re.match(pattern, script_stripped):
            is_allowed = True
            break

    if not is_allowed:
        return False, "Script does not match any allowed pattern. Only simple field access and arithmetic operations are permitted."

    return True, "Script is valid"


def validate_field_name(field_name):
    """Validate field names to prevent injection."""
    if not isinstance(field_name, str):
        return False, "Field name must be a string"
    if not re.match(r'^[a-zA-Z_][a-zA-Z0-9_\.]*$', field_name):
        return False, "Invalid field name format"
    if len(field_name) > 100:
        return False, "Field name too long"
    return True, "Valid"


def validate_index_name(index_name):
    """Validate index names to prevent injection."""
    if not isinstance(index_name, str):
        return False, "Index name must be a string"
    if not re.match(r'^[a-zA-Z0-9_\-\.]+$', index_name):
        return False, "Invalid index name format"
    if len(index_name) > 100:
        return False, "Index name too long"
    return True, "Valid"


def validate_params(params):
    """Validate script parameters - only allow numeric and string values."""
    if params is None:
        return True, "Valid"
    if not isinstance(params, dict):
        return False, "Params must be a dictionary"
    for key, value in params.items():
        if not re.match(r'^[a-zA-Z_][a-zA-Z0-9_]*$', str(key)):
            return False, f"Invalid parameter name: {key}"
        if not isinstance(value, (int, float, str, bool)):
            return False, f"Parameter '{key}' has unsupported type. Only int, float, str, bool allowed."
        if isinstance(value, str) and len(value) > 200:
            return False, f"Parameter '{key}' value too long"
    return True, "Valid"


@app.route("/api/scripted_aggregation", methods=["POST"])
def scripted_aggregation():
    """
    Execute a scripted metric aggregation on Elasticsearch.

    Expected JSON body:
    {
        "index": "my-index",
        "script": "doc['price'].value * doc['quantity'].value",
        "agg_type": "sum",
        "agg_name": "custom_agg",
        "lang": "painless",
        "params": {"factor": 1.5},
        "query": {"match_all": {}}
    }
    """
    try:
        data = request.get_json()
        if not data:
            return jsonify({"error": "Request body must be JSON"}), 400

        # Extract and validate required fields
        index = data.get("index")
        script_source = data.get("script")
        agg_type = data.get("agg_type", "sum")
        agg_name = data.get("agg_name", "scripted_agg")
        lang = data.get("lang", "painless")
        params = data.get("params", None)
        query = data.get("query", {"match_all": {}})

        # Validate index
        if not index:
            return jsonify({"error": "Index name is required"}), 400
        valid, msg = validate_index_name(index)
        if not valid:
            return jsonify({"error": msg}), 400

        # Validate script
        if not script_source:
            return jsonify({"error": "Script source is required"}), 400
        valid, msg = validate_script(script_source)
        if not valid:
            return jsonify({"error": f"Script validation failed: {msg}"}), 400

        # Validate aggregation type
        if agg_type not in ALLOWED_AGG_TYPES:
            return jsonify({
                "error": f"Aggregation type '{agg_type}' not allowed. Allowed types: {sorted(ALLOWED_AGG_TYPES)}"
            }), 400

        # Validate aggregation name
        if not re.match(r'^[a-zA-Z_][a-zA-Z0-9_]*$', str(agg_name)):
            return jsonify({"error": "Invalid aggregation name format"}), 400

        # Validate language
        if lang not in ALLOWED_LANGUAGES:
            return jsonify({
                "error": f"Script language '{lang}' not allowed. Allowed: {sorted(ALLOWED_LANGUAGES)}"
            }), 400

        # Validate params
        valid, msg = validate_params(params)
        if not valid:
            return jsonify({"error": msg}), 400

        # Build the script object
        script = {
            "lang": lang,
            "source": script_source,
        }
        if params:
            script["params"] = params

        # Build the aggregation query
        agg_body = {
            agg_name: {
                agg_type: {
                    "script": script
                }
            }
        }

        # Build the full search body
        search_body = {
            "size": 0,
            "query": query,
            "aggs": agg_body,
        }

        # Execute the search
        result = es.search(index=index, body=search_body)

        # Extract aggregation results
        agg_result = result.get("aggregations", {}).get(agg_name, {})

        return jsonify({
            "success": True,
            "index": index,
            "aggregation_name": agg_name,
            "aggregation_type": agg_type,
            "result": agg_result,
            "total_hits": result.get("hits", {}).get("total", {}).get("value", 0),
        })

    except json.JSONDecodeError:
        return jsonify({"error": "Invalid JSON in request body"}), 400
    except Exception as e:
        return jsonify({"error": f"Elasticsearch error: {str(e)}"}), 500


@app.route("/api/predefined_aggregation", methods=["POST"])
def predefined_aggregation():
    """
    Execute a predefined aggregation using parameterized templates.
    This is the safer alternative that uses predefined script templates.

    Expected JSON body:
    {
        "index": "my-index",
        "template": "field_arithmetic",
        "params": {
            "field1": "price",
            "field2": "quantity"
        },
        "agg_type": "sum",
        "agg_name": "total_revenue",
        "query": {"match_all": {}}
    }
    """
    # Predefined script templates - safer approach
    SCRIPT_TEMPLATES = {
        "single_field": "doc['{field}'].value",
        "field_multiply_factor": "doc['{field}'].value * params.factor",
        "field_arithmetic": "doc['{field1}'].value * doc['{field2}'].value",
        "field_sum": "doc['{field1}'].value + doc['{field2}'].value",
        "field_difference": "doc['{field1}'].value - doc['{field2}'].value",
        "field_ratio": "doc['{field2}'].value != 0 ? doc['{field1}'].value / doc['{field2}'].value : 0",
    }

    try:
        data = request.get_json()
        if not data:
            return jsonify({"error": "Request body must be JSON"}), 400

        index = data.get("index")
        template_name = data.get("template")
        template_params = data.get("params", {})
        agg_type = data.get("agg_type", "sum")
        agg_name = data.get("agg_name", "predefined_agg")
        script_params = data.get("script_params", None)
        query = data.get("query", {"match_all": {}})

        # Validate index
        if not index:
            return jsonify({"error": "Index name is required"}), 400
        valid, msg = validate_index_name(index)
        if not valid:
            return jsonify({"error": msg}), 400

        # Validate template
        if template_name not in SCRIPT_TEMPLATES:
            return jsonify({
                "error": f"Unknown template '{template_name}'. Available: {sorted(SCRIPT_TEMPLATES.keys())}"
            }), 400

        # Validate aggregation type
        if agg_type not in ALLOWED_AGG_TYPES:
            return jsonify({
                "error": f"Aggregation type '{agg_type}' not allowed. Allowed types: {sorted(ALLOWED_AGG_TYPES)}"
            }), 400

        # Validate aggregation name
        if not re.match(r'^[a-zA-Z_][a-zA-Z0-9_]*$', str(agg_name)):
            return jsonify({"error": "Invalid aggregation name format"}), 400

        # Validate template parameters (field names)
        for key, value in template_params.items():
            if key.startswith("field"):
                valid, msg = validate_field_name(value)
                if not valid:
                    return jsonify({"error": f"Invalid field name for '{key}': {msg}"}), 400

        # Validate script params
        valid, msg = validate_params(script_params)
        if not valid:
            return jsonify({"error": msg}), 400

        # Build script from template
        script_source = SCRIPT_TEMPLATES[template_name].format(**template_params)

        # Build script object
        script = {
            "lang": "painless",
            "source": script_source,
        }
        if script_params:
            script["params"] = script_params

        # Build and execute search
        search_body = {
            "size": 0,
            "query": query,
            "aggs": {
                agg_name: {
                    agg_type: {
                        "script": script
                    }
                }
            },
        }

        result = es.search(index=index, body=search_body)
        agg_result = result.get("aggregations", {}).get(agg_name, {})

        return jsonify({
            "success": True,
            "index": index,
            "template": template_name,
            "aggregation_name": agg_name,
            "aggregation_type": agg_type,
            "result": agg_result,
            "total_hits": result.get("hits", {}).get("total", {}).get("value", 0),
        })

    except KeyError as e:
        return jsonify({"error": f"Missing template parameter: {str(e)}"}), 400
    except Exception as e:
        return jsonify({"error": f"Elasticsearch error: {str(e)}"}), 500


