@app.route("/api/health", methods=["GET"])
def health():
    """Health check endpoint."""
    try:
        info = es.info()
        return jsonify({
            "status": "healthy",
            "elasticsearch": {
                "cluster_name": info.get("cluster_name"),
                "version": info.get("version", {}).get("number"),
            },
        })
    except Exception as e:
        return jsonify({
            "status": "unhealthy",
            "error": str(e),
        }), 503


